#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

from dataclasses import dataclass, field
from pathlib import Path
import json
import re

from wiki_section import KNOWN_EDGE_TYPES, extract_section_links, list_section_ids, page_type

DEFAULT_IGNORED_DIR_NAMES = {"draft", "archive", "examples"}
AUTO_START = "<!-- superpower-adapter:auto:start -->"
AUTO_END = "<!-- superpower-adapter:auto:end -->"
PROJECT_WIKI_REL = Path(".superpowers") / "wiki"
SHARED_WIKI_REL = Path(".shared-superpowers") / "wiki"
PROJECT_SETTINGS_REL = Path(".superpowers") / "settings.json"
SHARED_SETTINGS_REL = Path(".shared-superpowers") / "settings.json"
WIKI_POLICY_SKIP = "skip"
WIKI_POLICY_ASK = "ask"
WIKI_POLICY_REFUSE = "refuse"
WIKI_POLICY_VALUES = {WIKI_POLICY_SKIP, WIKI_POLICY_ASK, WIKI_POLICY_REFUSE}
WIKI_OPERATION_UPDATE = "updateExistingPage"
WIKI_OPERATION_CREATE = "createNewDocument"
DEFAULT_WIKI_UPDATE_AUTHORIZATION = {
    WIKI_OPERATION_UPDATE: WIKI_POLICY_SKIP,
    WIKI_OPERATION_CREATE: WIKI_POLICY_ASK,
}
DEFAULT_SHARED_WIKI_NEUTRALITY = {
    "blockedTerms": [],
    "blockedPatterns": [],
}
# Per-project shared-wiki MCP connection block (.shared-superpowers/settings.json
# -> wiki.sharedMcp). This is the same block the MCP server self-configures from
# via CLAUDE_PROJECT_DIR; the adapter reads it only to report binding state.
# cacheDir is intentionally not a project-level field (machine-local).
SHARED_MCP_STRING_FIELDS = ("repoUrl", "baseBranch", "remote", "wikiRoot", "displayRoot")
ENTRY_STUB = "# Project Wiki\n\nUse this file as the entry point for project-specific wiki pages.\n\n" + AUTO_START + "\n" + AUTO_END + "\n"


@dataclass(frozen=True)
class WikiRoot:
    name: str
    path: Path
    display_path: str


@dataclass(frozen=True)
class IndexReference:
    source: Path
    raw: str
    target: Path
    kind: str


@dataclass
class WikiIndexGraph:
    wiki_root: Path
    indexes: list[Path] = field(default_factory=list)
    leaves: list[Path] = field(default_factory=list)
    directories: list[Path] = field(default_factory=list)
    missing: list[str] = field(default_factory=list)
    invalid: list[str] = field(default_factory=list)
    cycles: list[str] = field(default_factory=list)

    @property
    def files(self) -> list[Path]:
        return [*self.indexes, *self.leaves]

    @property
    def warnings(self) -> list[str]:
        return [*self.invalid, *self.missing, *self.cycles]


@dataclass
class SectionGraph:
    """Section-level knowledge graph derived from [[page#section]] wikilinks.

    Nodes are addressed as "rel/path.md#section-id"; a page-level edge target (a
    [[page]] without an anchor) is the bare "rel/path.md". This is a wiki-layer
    artifact, orthogonal to the plan-side wiki-context schema; it is consumed by
    maintenance (update-wiki) and lint (doctor), never by execution-time context.
    """

    wiki_root: Path
    nodes: list[str] = field(default_factory=list)
    edges: list[dict] = field(default_factory=list)
    backlinks: dict[str, list[str]] = field(default_factory=dict)
    dangling: list[dict] = field(default_factory=list)
    page_types: dict[str, str] = field(default_factory=dict)

    def to_payload(self) -> dict:
        return {
            "schema": "section-graph/3",
            "nodes": self.nodes,
            "pageTypes": self.page_types,
            "edges": self.edges,
            "backlinks": self.backlinks,
            "dangling": self.dangling,
        }


def write_text_lf(path: Path, content: str) -> None:
    """Write UTF-8 text with LF newlines, regardless of platform.

    ``Path.write_text`` uses text mode, which on Windows translates ``\\n`` to ``\\r\\n``
    and produces CRLF artifacts that churn against LF-committed wiki files (e.g. a
    regenerated ``.graph.json`` showing a whole-file diff with no semantic change).
    Pinning ``newline="\\n"`` keeps generated indexes / graphs / pages byte-deterministic
    across platforms.
    """
    with path.open("w", encoding="utf-8", newline="\n") as handle:
        handle.write(content)


def repo_root(start: Path) -> Path:
    current = start.resolve()
    for candidate in (current, *current.parents):
        if (candidate / ".superpowers").exists() or (candidate / ".shared-superpowers").exists() or (candidate / "superpowers").exists():
            return candidate
    return current


def known_wiki_roots(project_root: Path) -> list[WikiRoot]:
    project_root = project_root.resolve()
    return [
        WikiRoot("project", project_root / PROJECT_WIKI_REL, PROJECT_WIKI_REL.as_posix()),
        WikiRoot("shared", project_root / SHARED_WIKI_REL, SHARED_WIKI_REL.as_posix()),
    ]


def wiki_root_from_dir(wiki_dir: Path, kind: str = "shared") -> WikiRoot:
    """A WikiRoot whose content is rooted directly at ``wiki_dir``.

    The standard layout nests the wiki under ``.superpowers/wiki`` or
    ``.shared-superpowers/wiki`` inside a project root. A standalone wiki
    repository instead keeps ``index.md`` and the page tree at the repository
    root, so the repo-local author/migrate skills point the CLI at the repo with
    ``--wiki-dir``. The display prefix is empty (display == the page's rel path),
    and ``kind`` defaults to ``shared`` so neutrality guards apply and settings
    resolve to ``<wiki_dir>/.shared-superpowers/settings.json`` when the caller
    passes ``wiki_dir`` as the project root.
    """
    return WikiRoot(kind, Path(wiki_dir).resolve(), "")


def wiki_root_by_name(project_root: Path, name: str) -> WikiRoot:
    for root in known_wiki_roots(project_root):
        if root.name == name:
            return root
    raise ValueError(f"Unknown wiki root: {name}")


def existing_wiki_roots(project_root: Path, require_index: bool = True) -> list[WikiRoot]:
    roots: list[WikiRoot] = []
    for root in known_wiki_roots(project_root):
        if require_index:
            if (root.path / "index.md").is_file():
                roots.append(root)
        elif root.path.is_dir():
            roots.append(root)
    return roots


def select_wiki_root(project_root: Path, selector: str = "project", create: bool = False) -> WikiRoot:
    root = wiki_root_by_name(project_root, selector)
    if create:
        root.path.mkdir(parents=True, exist_ok=True)
    return root


def selected_wiki_roots(project_root: Path, selector: str = "all", require_index: bool = True) -> list[WikiRoot]:
    if selector == "all":
        return existing_wiki_roots(project_root, require_index=require_index)
    if selector in {"project", "shared"}:
        root = wiki_root_by_name(project_root, selector)
        if require_index and not (root.path / "index.md").is_file():
            return []
        if not require_index and not root.path.is_dir():
            return []
        return [root]
    raise ValueError(f"Unknown wiki root selector: {selector}")


def display_wiki_path(root: WikiRoot, file_path: Path) -> str:
    rel = rel_posix(root.path.resolve(), file_path.resolve())
    prefix = root.display_path.strip().strip("/")
    return f"{prefix}/{rel}" if prefix else rel


def wiki_settings_path(project_root: Path, root: WikiRoot) -> Path:
    if root.name == "project":
        return project_root / PROJECT_SETTINGS_REL
    if root.name == "shared":
        return project_root / SHARED_SETTINGS_REL
    raise ValueError(f"Unknown wiki root: {root.name}")


def _load_settings_payload(settings_path: Path) -> dict:
    if not settings_path.is_file():
        return {}

    try:
        payload = json.loads(settings_path.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        raise ValueError(f"Invalid JSON in {settings_path}: {exc}") from exc
    if not isinstance(payload, dict):
        raise ValueError(f"Settings must be a JSON object: {settings_path}")
    return payload


def _wiki_settings_from_payload(payload: dict, settings_path: Path) -> dict:
    wiki_settings = payload.get("wiki", {})
    if wiki_settings is None:
        return {}
    if not isinstance(wiki_settings, dict):
        raise ValueError(f"wiki settings must be an object in {settings_path}")
    return wiki_settings


def load_wiki_settings(project_root: Path, root: WikiRoot) -> dict:
    settings_path = wiki_settings_path(project_root, root)
    return _wiki_settings_from_payload(_load_settings_payload(settings_path), settings_path)


def _read_string_list(settings_path: Path, payload: dict, key: str) -> list[str]:
    value = payload.get(key, [])
    if value is None:
        return []
    if not isinstance(value, list) or any(not isinstance(item, str) for item in value):
        raise ValueError(f"wiki.sharedNeutrality.{key} must be a string array in {settings_path}")
    return value


def load_wiki_update_authorization_policy(project_root: Path, root: WikiRoot) -> dict[str, str]:
    settings_path = wiki_settings_path(project_root, root)
    policy = dict(DEFAULT_WIKI_UPDATE_AUTHORIZATION)
    wiki_settings = load_wiki_settings(project_root, root)

    update_auth = wiki_settings.get("updateAuthorization", {})
    if update_auth is None:
        update_auth = {}
    if not isinstance(update_auth, dict):
        raise ValueError(f"wiki.updateAuthorization must be an object in {settings_path}")

    for operation in DEFAULT_WIKI_UPDATE_AUTHORIZATION:
        value = update_auth.get(operation, policy[operation])
        if value not in WIKI_POLICY_VALUES:
            allowed = ", ".join(sorted(WIKI_POLICY_VALUES))
            raise ValueError(f"Invalid wiki.updateAuthorization.{operation} in {settings_path}: {value!r}; expected one of {allowed}")
        policy[operation] = value
    return policy


def load_shared_wiki_neutrality_policy(project_root: Path, root: WikiRoot) -> dict[str, list[str]]:
    if root.name != "shared":
        return dict(DEFAULT_SHARED_WIKI_NEUTRALITY)

    settings_path = wiki_settings_path(project_root, root)
    wiki_settings = load_wiki_settings(project_root, root)
    neutrality = wiki_settings.get("sharedNeutrality", {})
    if neutrality is None:
        neutrality = {}
    if not isinstance(neutrality, dict):
        raise ValueError(f"wiki.sharedNeutrality must be an object in {settings_path}")

    policy = {
        "blockedTerms": _read_string_list(settings_path, neutrality, "blockedTerms"),
        "blockedPatterns": _read_string_list(settings_path, neutrality, "blockedPatterns"),
    }
    for pattern in policy["blockedPatterns"]:
        try:
            re.compile(pattern)
        except re.error as exc:
            raise ValueError(f"Invalid wiki.sharedNeutrality.blockedPatterns entry in {settings_path}: {pattern!r}: {exc}") from exc
    return policy


def load_shared_wiki_mcp_binding(project_root: Path) -> dict[str, object] | None:
    """Read the per-project shared-wiki MCP connection block.

    Returns None when `.shared-superpowers/settings.json` declares no
    `wiki.sharedMcp` block (the project binds no shared wiki MCP -> fail-closed,
    no MCP shared wiki for this project), otherwise a dict of the recognized
    connection fields. This is the same block the MCP server self-configures from
    via CLAUDE_PROJECT_DIR; the adapter reads it only to report binding state
    (e.g. doctor). Unknown keys are ignored to match the server; cacheDir is not a
    project-level field. Field types are validated so doctor surfaces mistakes.
    """
    settings_path = project_root.resolve() / SHARED_SETTINGS_REL
    wiki_settings = _wiki_settings_from_payload(_load_settings_payload(settings_path), settings_path)
    binding = wiki_settings.get("sharedMcp")
    if binding is None:
        return None
    if not isinstance(binding, dict):
        raise ValueError(f"wiki.sharedMcp must be an object in {settings_path}")

    result: dict[str, object] = {}
    for key in SHARED_MCP_STRING_FIELDS:
        value = binding.get(key)
        if value is None:
            continue
        if not isinstance(value, str) or not value.strip():
            raise ValueError(f"wiki.sharedMcp.{key} must be a non-empty string in {settings_path}")
        result[key] = value
    draft = binding.get("draftPr")
    if draft is not None:
        if not isinstance(draft, bool):
            raise ValueError(f"wiki.sharedMcp.draftPr must be a boolean in {settings_path}")
        result["draftPr"] = draft
    return result


def shared_wiki_neutrality_violations(project_root: Path, root: WikiRoot, text: str, label: str) -> list[str]:
    if root.name != "shared":
        return []

    policy = load_shared_wiki_neutrality_policy(project_root, root)
    violations: list[str] = []
    for term in policy["blockedTerms"]:
        if term and term in text:
            violations.append(f"{label}: blocked term {term!r}")
    for pattern in policy["blockedPatterns"]:
        if pattern and re.search(pattern, text):
            violations.append(f"{label}: blocked pattern {pattern!r}")
    return violations


def enforce_shared_wiki_neutrality(project_root: Path, root: WikiRoot, text: str, label: str) -> None:
    violations = shared_wiki_neutrality_violations(project_root, root, text, label)
    if violations:
        details = "; ".join(violations)
        raise ValueError(f"Shared wiki requires neutral/portable content; remove system-specific identifiers before writing. {details}")


def wiki_update_operation_for_target(target_exists: bool) -> str:
    return WIKI_OPERATION_UPDATE if target_exists else WIKI_OPERATION_CREATE


def enforce_wiki_update_authorization(
    project_root: Path,
    root: WikiRoot,
    operation: str,
    *,
    authorized_update: bool = False,
    authorized_create: bool = False,
) -> None:
    policy = load_wiki_update_authorization_policy(project_root, root)
    action = policy[operation]
    if action == WIKI_POLICY_SKIP:
        return
    if action == WIKI_POLICY_REFUSE:
        raise PermissionError(f"{root.display_path} policy refuses wiki operation {operation}")

    authorized = authorized_update if operation == WIKI_OPERATION_UPDATE else authorized_create
    if not authorized:
        flag = "--authorized-update" if operation == WIKI_OPERATION_UPDATE else "--authorized-create"
        raise PermissionError(f"{root.display_path} policy requires user authorization for {operation}; rerun after approval with {flag}")


def parse_root_prefixed_wiki_path(project_root: Path, value: str) -> tuple[WikiRoot, Path] | None:
    clean = value.strip().strip("/")
    for root in known_wiki_roots(project_root):
        prefix = root.display_path.rstrip("/")
        if clean == prefix:
            return root, Path("index.md")
        if clean.startswith(prefix + "/"):
            return root, Path(clean[len(prefix) + 1:])
    return None


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def load_ignored_dir_names(wiki_root: Path) -> set[str]:
    ignored = set(DEFAULT_IGNORED_DIR_NAMES)
    ignore_file = wiki_root / ".adapter-ignore"
    if ignore_file.is_file():
        for line in ignore_file.read_text(encoding="utf-8").splitlines():
            value = line.strip()
            if not value or value.startswith("#"):
                continue
            ignored.add(value)
    return ignored


def is_ignored_directory(path: Path, ignored_dir_names: set[str]) -> bool:
    return path.name in ignored_dir_names or path.name.startswith(".")


def relevant_markdown_files(directory: Path) -> list[Path]:
    return sorted(
        path
        for path in directory.iterdir()
        if path.is_file() and path.suffix == ".md" and path.name != "index.md"
    )


def summary_from_markdown(path: Path) -> str:
    try:
        lines = read_text(path).splitlines()
    except OSError:
        return ""

    title = ""
    summary = ""
    for line in lines:
        stripped = line.strip()
        if not stripped or stripped.startswith("<!--"):
            # Blank lines and HTML comments (wiki-section markers included) carry no summary.
            continue
        if stripped.startswith("#"):
            # The first heading is the page title. A LATER heading is not a summary — it is
            # the first section's ## on a section-ized page whose title is immediately
            # followed by a wiki-section marker and no prose. Skip it and keep looking for
            # real prose; grabbing it verbatim produced garbage like "Title — ## Subheading".
            if not title:
                title = stripped.lstrip("#").strip()
            continue
        summary = stripped
        break

    if title and summary:
        return f"{title} — {summary}"
    if title:
        return title
    return summary


def has_relevant_content(directory: Path, ignored_dir_names: set[str]) -> bool:
    if relevant_markdown_files(directory):
        return True
    return any(
        has_relevant_content(child, ignored_dir_names)
        for child in directory.iterdir()
        if child.is_dir() and not is_ignored_directory(child, ignored_dir_names)
    )


def relevant_child_directories(directory: Path, ignored_dir_names: set[str]) -> list[Path]:
    return sorted(
        child
        for child in directory.iterdir()
        if child.is_dir()
        and not is_ignored_directory(child, ignored_dir_names)
        and has_relevant_content(child, ignored_dir_names)
    )


def child_directory_summary(directory: Path, ignored_dir_names: set[str]) -> str:
    leaf_files = relevant_markdown_files(directory)
    if leaf_files:
        return summary_from_markdown(leaf_files[0])

    for child in relevant_child_directories(directory, ignored_dir_names):
        summary = child_directory_summary(child, ignored_dir_names)
        if summary:
            return summary

    index_path = directory / "index.md"
    if index_path.is_file():
        return summary_from_markdown(index_path)
    return ""


def is_path_within(root: Path, target: Path) -> bool:
    try:
        target.relative_to(root)
        return True
    except ValueError:
        return False


def rel_posix(root: Path, target: Path) -> str:
    return target.relative_to(root).as_posix()


def replace_auto_section(text: str, content: str) -> str:
    if AUTO_START not in text or AUTO_END not in text:
        text = text.rstrip() + "\n\n" + AUTO_START + "\n" + AUTO_END + "\n"
    start = text.index(AUTO_START) + len(AUTO_START)
    end = text.index(AUTO_END)
    body = "\n" + content.rstrip() + "\n" if content.strip() else "\n"
    return text[:start] + body + text[end:]


def _looks_like_wiki_ref(value: str) -> bool:
    clean = value.split("#", 1)[0].strip()
    return bool(clean) and (clean.endswith("/") or clean.endswith(".md") or clean.endswith(".markdown") or clean.endswith(".mdx"))


def _candidate_refs(text: str) -> list[str]:
    refs: list[str] = []
    in_fence = False
    for line in text.splitlines():
        stripped = line.strip()
        if stripped.startswith("```") or stripped.startswith("````"):
            in_fence = not in_fence
            continue
        if in_fence:
            continue
        for match in re.finditer(r"\[[^\]]+\]\(([^)]+)\)", line):
            raw = match.group(1).strip()
            if _looks_like_wiki_ref(raw):
                refs.append(raw)
        for match in re.finditer(r"`([^`]+)`", line):
            raw = match.group(1).strip()
            if _looks_like_wiki_ref(raw):
                refs.append(raw)
        match = re.match(r"^[-*]\s+([^\s`][^\s]*(?:\.md|\.markdown|\.mdx|/))\s*(?:$|[—#])", stripped)
        if match:
            raw = match.group(1).strip()
            if _looks_like_wiki_ref(raw):
                refs.append(raw)
    return list(dict.fromkeys(refs))


def _is_external_ref(raw: str) -> bool:
    lowered = raw.lower()
    return (
        not raw
        or raw.startswith("#")
        or "://" in raw
        or lowered.startswith("mailto:")
        or raw.startswith("/")
    )


def _has_hidden_part(path: Path) -> bool:
    return any(part.startswith(".") and part not in {".", ".."} for part in path.parts)


def _resolve_reference(index_path: Path, wiki_root: Path, raw: str, ignored_dir_names: set[str]) -> tuple[Path | None, str, str | None]:
    clean = raw.split("#", 1)[0].strip()
    if _is_external_ref(clean):
        return None, "invalid", f"Ignored unsupported reference from {rel_posix(wiki_root, index_path)}: {raw}"

    rel_path = Path(clean)
    if any(part == ".." for part in rel_path.parts):
        return None, "invalid", f"Rejected escaping reference from {rel_posix(wiki_root, index_path)}: {raw}"
    if _has_hidden_part(rel_path):
        return None, "invalid", f"Rejected hidden-path reference from {rel_posix(wiki_root, index_path)}: {raw}"
    if any(part in ignored_dir_names for part in rel_path.parts[:-1]):
        return None, "invalid", f"Rejected ignored-directory reference from {rel_posix(wiki_root, index_path)}: {raw}"

    candidate = (index_path.parent / rel_path).resolve()
    if not is_path_within(wiki_root.resolve(), candidate):
        return None, "invalid", f"Rejected out-of-wiki reference from {rel_posix(wiki_root, index_path)}: {raw}"

    is_directory_ref = clean.endswith("/") or (candidate.exists() and candidate.is_dir())
    if is_directory_ref:
        candidate = candidate / "index.md"
        kind = "index"
    elif candidate.name == "index.md":
        kind = "index"
    elif candidate.suffix == ".md":
        kind = "leaf"
    else:
        return None, "invalid", f"Rejected non-markdown reference from {rel_posix(wiki_root, index_path)}: {raw}"

    return candidate.resolve(), kind, None


def parse_index_references(index_path: Path, wiki_root: Path) -> list[IndexReference]:
    ignored_dir_names = load_ignored_dir_names(wiki_root)
    text = index_path.read_text(encoding="utf-8") if index_path.is_file() else ""
    references: list[IndexReference] = []
    for raw in _candidate_refs(text):
        target, kind, _ = _resolve_reference(index_path, wiki_root, raw, ignored_dir_names)
        if target is not None:
            references.append(IndexReference(index_path, raw, target, kind))
    return references


def build_wiki_index_graph(wiki_root: Path) -> WikiIndexGraph:
    graph = WikiIndexGraph(wiki_root=wiki_root.resolve())
    ignored_dir_names = load_ignored_dir_names(wiki_root)
    root_index = (wiki_root / "index.md").resolve()
    visited: set[Path] = set()
    visiting: set[Path] = set()
    seen_leaves: set[Path] = set()
    seen_dirs: set[Path] = set()

    def add_index(index_path: Path) -> None:
        if index_path in visiting:
            graph.cycles.append(f"Cycle detected at {rel_posix(wiki_root.resolve(), index_path)}")
            return
        if index_path in visited:
            return
        if not index_path.is_file():
            graph.missing.append(f"Missing index: {rel_posix(wiki_root.resolve(), index_path)}")
            return

        visiting.add(index_path)
        visited.add(index_path)
        graph.indexes.append(index_path)
        try:
            text = index_path.read_text(encoding="utf-8")
        except OSError as exc:
            graph.invalid.append(f"Could not read {rel_posix(wiki_root.resolve(), index_path)}: {exc}")
            visiting.remove(index_path)
            return

        for raw in _candidate_refs(text):
            target, kind, error = _resolve_reference(index_path, wiki_root.resolve(), raw, ignored_dir_names)
            if error:
                graph.invalid.append(error)
                continue
            if target is None:
                continue
            if kind == "index":
                directory = target.parent
                if directory not in seen_dirs:
                    seen_dirs.add(directory)
                    graph.directories.append(directory)
                if target.exists():
                    add_index(target)
                else:
                    graph.missing.append(f"Missing index referenced from {rel_posix(wiki_root.resolve(), index_path)}: {raw}")
            elif target.exists() and target.is_file():
                if target not in seen_leaves:
                    seen_leaves.add(target)
                    graph.leaves.append(target)
            else:
                graph.missing.append(f"Missing wiki page referenced from {rel_posix(wiki_root.resolve(), index_path)}: {raw}")

        visiting.remove(index_path)

    if root_index.is_file():
        add_index(root_index)
    else:
        graph.missing.append("Missing index: index.md")

    graph.indexes.sort(key=lambda path: (path != root_index, rel_posix(wiki_root.resolve(), path)))
    graph.leaves.sort(key=lambda path: rel_posix(wiki_root.resolve(), path))
    graph.directories.sort(key=lambda path: rel_posix(wiki_root.resolve(), path))
    return graph


def _resolve_section_link_page(
    source_leaf: Path,
    wiki_root: Path,
    page: str,
    ignored_dir_names: set[str],
) -> tuple[Path | None, str | None]:
    """Resolve the page part of a [[page#section]] link to a file path.

    Page paths are wiki-root-relative so a given edge means the same thing
    regardless of which page declares it. An empty page denotes a same-page link.
    Returns (resolved_path, reason); reason is set only on rejection.
    """
    clean = page.strip()
    if not clean:
        return source_leaf.resolve(), None
    if _is_external_ref(clean):
        return None, "external or unsupported reference"

    if clean.endswith((".md", ".markdown", ".mdx")):
        rel_str = clean
    elif clean.endswith("/"):
        rel_str = clean + "index.md"
    else:
        rel_str = clean + ".md"

    rel_path = Path(rel_str)
    if any(part == ".." for part in rel_path.parts):
        return None, "reference escapes the wiki root"
    if _has_hidden_part(rel_path):
        return None, "reference points into a hidden path"
    if any(part in ignored_dir_names for part in rel_path.parts[:-1]):
        return None, "reference points into an ignored directory"

    candidate = (wiki_root.resolve() / rel_path).resolve()
    if not is_path_within(wiki_root.resolve(), candidate):
        return None, "reference resolves outside the wiki root"
    return candidate, None


def build_section_graph(wiki_root: Path) -> SectionGraph:
    """Build the section-level [[page#section]] graph for one wiki root.

    Reuses build_wiki_index_graph to enumerate indexed leaf pages, then parses the
    [[ ]] knowledge edges in each section. A target is dangling when its page is
    unresolvable/missing or its named section does not exist. build_wiki_index_graph
    itself is left untouched (it intentionally strips anchors for page discovery).
    """
    wiki_root_resolved = wiki_root.resolve()
    graph = SectionGraph(wiki_root=wiki_root_resolved)
    ignored_dir_names = load_ignored_dir_names(wiki_root)
    leaves = build_wiki_index_graph(wiki_root).leaves

    section_ids_by_page: dict[Path, set[str]] = {}

    def section_ids_for(path: Path) -> set[str]:
        resolved = path.resolve()
        if resolved not in section_ids_by_page:
            try:
                text = resolved.read_text(encoding="utf-8")
                section_ids_by_page[resolved] = set(list_section_ids(text))
            except OSError:
                section_ids_by_page[resolved] = set()
        return section_ids_by_page[resolved]

    for leaf in leaves:
        leaf_rel = rel_posix(wiki_root_resolved, leaf)
        try:
            text = leaf.read_text(encoding="utf-8")
        except OSError as exc:
            graph.dangling.append({"from": leaf_rel, "raw": "", "reason": f"could not read page: {exc}"})
            continue

        for section_id in list_section_ids(text):
            graph.nodes.append(f"{leaf_rel}#{section_id}")
        graph.page_types[leaf_rel] = page_type(text)

        for section_id, links in extract_section_links(text).items():
            source_node = f"{leaf_rel}#{section_id}"
            for page, target_section, edge_type in links:
                type_prefix = f"{edge_type}: " if edge_type != "see-also" else ""
                raw = f"[[{type_prefix}{page}{('#' + target_section) if target_section else ''}]]"
                if edge_type not in KNOWN_EDGE_TYPES:
                    graph.dangling.append({
                        "from": source_node,
                        "raw": raw,
                        "reason": f"unknown edge type '{edge_type}' (expected: {', '.join(KNOWN_EDGE_TYPES)})",
                    })
                    continue
                target_path, reason = _resolve_section_link_page(leaf, wiki_root_resolved, page, ignored_dir_names)
                if reason is not None:
                    graph.dangling.append({"from": source_node, "raw": raw, "reason": reason})
                    continue
                if not target_path.is_file():
                    graph.dangling.append({"from": source_node, "raw": raw, "reason": "target page does not exist"})
                    continue

                target_rel = rel_posix(wiki_root_resolved, target_path)
                if target_section is not None and target_section not in section_ids_for(target_path):
                    graph.dangling.append(
                        {"from": source_node, "raw": raw, "reason": f"target section '{target_section}' not found in {target_rel}"}
                    )
                    continue

                target_node = f"{target_rel}#{target_section}" if target_section else target_rel
                graph.edges.append({"from": source_node, "to": target_node, "type": edge_type, "raw": raw})
                graph.backlinks.setdefault(target_node, []).append({"from": source_node, "type": edge_type})

    graph.nodes = sorted(dict.fromkeys(graph.nodes))
    graph.page_types = dict(sorted(graph.page_types.items()))
    graph.edges.sort(key=lambda edge: (edge["from"], edge["to"], edge["type"]))
    graph.backlinks = {
        key: [{"from": frm, "type": typ} for frm, typ in sorted({(b["from"], b["type"]) for b in value})]
        for key, value in sorted(graph.backlinks.items())
    }
    graph.dangling.sort(key=lambda item: (item["from"], item["raw"]))
    return graph


_WIKI_DISPLAY_PREFIXES = (".shared-superpowers/wiki/", ".superpowers/wiki/")
_WIKI_MD_SUFFIXES = (".md", ".markdown", ".mdx")


def normalize_graph_node(node: str) -> str:
    """Normalize a query node id to the persisted graph's canonical key form.

    The graph keys a page wiki-root-relative and with a ``.md`` suffix
    (``frontend/type-safety.md#enum-const-enum``). Callers, however, routinely hold a page
    in the shape the *read* path accepts instead: display-root-prefixed
    (``.shared-superpowers/wiki/…`` / ``.superpowers/wiki/…``), ``./``-prefixed, or the
    ``.md``-less form that ``[[page#section]]`` link text and companion index tables show.
    Those forms all resolve for read-sections (via ``normalizeWikiRelativePath``) but, before
    this, silently missed every graph lookup and returned empty edges. Mirror that read-path
    normalization so any identifier read-sections resolves also resolves here: strip a
    display-root/``./`` prefix off the page part and append ``.md`` when it lacks a markdown
    suffix. The ``#section`` anchor (and a bare page node with no anchor) is preserved.
    Best-effort and idempotent — a node already in canonical form returns unchanged.
    """
    page, sep, section = node.partition("#")
    page = page.strip().replace("\\", "/")
    if page.startswith("./"):
        page = page[2:]
    for prefix in _WIKI_DISPLAY_PREFIXES:
        if page.startswith(prefix):
            page = page[len(prefix):]
            break
    if page and not page.endswith(_WIKI_MD_SUFFIXES):
        page = page + ".md"
    return f"{page}#{section}" if sep else page


def one_hop_neighbors(graph: dict, nodes: list[str]) -> dict[str, dict]:
    """Bounded 1-hop slice of a persisted ``section-graph`` payload.

    For each requested ``page#section`` (or bare ``page``) node, return its outgoing
    edges (``out``) and incoming backlinks (``in``). Output size scales with the number
    of requested nodes, never with the whole graph: this is the query that replaces
    "load the entire .graph.json into context". Unknown nodes yield empty lists. The
    function is pure (graph payload in, slice out); companion-index gating is layered on
    by callers that have the wiki filesystem.

    Each requested node is normalized to the graph's canonical key form before lookup (see
    ``normalize_graph_node``) so display-root-prefixed / ``.md``-less identifiers resolve the
    same way they do for read-sections; results stay keyed by the caller's original node
    string so callers map slices back to exactly what they asked for.
    """
    out_by_node: dict[str, list[dict]] = {}
    edges = graph.get("edges") if isinstance(graph, dict) else None
    if isinstance(edges, list):
        for edge in edges:
            if not isinstance(edge, dict):
                continue
            frm, to = edge.get("from"), edge.get("to")
            if isinstance(frm, str) and isinstance(to, str):
                out_by_node.setdefault(frm, []).append({"to": to, "type": edge.get("type")})

    backlinks = graph.get("backlinks") if isinstance(graph, dict) else None
    result: dict[str, dict] = {}
    for node in nodes:
        key = normalize_graph_node(node)
        incoming: list[dict] = []
        if isinstance(backlinks, dict):
            for src in backlinks.get(key, []) or []:
                if isinstance(src, dict) and isinstance(src.get("from"), str):
                    incoming.append({"from": src["from"], "type": src.get("type")})
        result[node] = {"out": out_by_node.get(key, []), "in": incoming}
    return result


def depends_on_closure_targets(
    slices: dict[str, dict],
    source_nodes: list[str],
    require_indexed: bool = False,
) -> list[tuple[str, str, str]]:
    """1-hop ``depends-on`` section targets out of a neighbors slice map.

    Shared closure primitive used by both the renderer's selection-time closure
    (``wiki_context_render._depends_on_closure_entries``, local graphs) and the
    materializer's github_mcp closure (``wiki_materialize_task``, the remote shared
    graph) so the two paths never fork on what counts as a closed edge.

    For each requested ``source_node``, return ``(closed_via_node, target_page,
    target_section)`` for every outgoing edge whose ``type`` is ``depends-on`` and
    whose target is a *section* (``page#section``). Page-level depends-on targets (no
    ``#``) are skipped — a whole page is not rereadable as one section. Bounded to one
    hop. Targets are deduped by ``(page, section)`` so the first source that references
    a target wins ``closed_via`` (matching emitted-order precedence). When
    ``require_indexed`` is set, only edges flagged ``indexed`` are followed — the shared
    graph marks whether a follow-up section read would pass the read whitelist, so an
    unindexed neighbor would only fail closed downstream.
    """
    targets: list[tuple[str, str, str]] = []
    seen: set[tuple[str, str]] = set()
    for source_node in source_nodes:
        slice_ = slices.get(source_node) or {}
        for edge in slice_.get("out", []) or []:
            if not isinstance(edge, dict) or edge.get("type") != "depends-on":
                continue
            if require_indexed and not edge.get("indexed"):
                continue
            target_node = edge.get("to") or ""
            if "#" not in target_node:
                continue
            page, _, section = target_node.rpartition("#")
            if not page or not section:
                continue
            dedup = (page, section)
            if dedup in seen:
                continue
            seen.add(dedup)
            targets.append((source_node, page, section))
    return targets


def iter_indexed_wiki_files(wiki_root: Path, include_indexes: bool = False) -> list[Path]:
    graph = build_wiki_index_graph(wiki_root)
    return graph.files if include_indexes else graph.leaves


def is_indexed_wiki_path(wiki_root: Path, path: Path, include_indexes: bool = True) -> bool:
    target = path.resolve()
    graph = build_wiki_index_graph(wiki_root)
    candidates = graph.files if include_indexes else graph.leaves
    return target in {item.resolve() for item in candidates}


def append_index_reference(wiki_root: Path, target: Path) -> None:
    wiki_root = wiki_root.resolve()
    target = target.resolve()
    if not is_path_within(wiki_root, target):
        raise ValueError(f"Target is outside wiki root: {target}")
    if target.suffix != ".md" or target.name == "index.md":
        raise ValueError(f"Target must be a non-index markdown wiki page: {rel_posix(wiki_root, target)}")

    root_index = wiki_root / "index.md"
    if not root_index.exists():
        root_index.parent.mkdir(parents=True, exist_ok=True)
        write_text_lf(root_index, ENTRY_STUB)

    rel = target.relative_to(wiki_root).as_posix()
    if is_indexed_wiki_path(wiki_root, target, include_indexes=False):
        return

    text = root_index.read_text(encoding="utf-8")
    line = f"- `{rel}`"
    if line in text:
        return

    if AUTO_START in text and AUTO_END in text:
        start = text.index(AUTO_START) + len(AUTO_START)
        end = text.index(AUTO_END)
        existing = [item.rstrip() for item in text[start:end].splitlines() if item.strip()]
        existing.append(line)
        content = "\n".join(dict.fromkeys(existing))
        write_text_lf(root_index, replace_auto_section(text, content))
        return

    write_text_lf(root_index, text.rstrip() + "\n\n" + AUTO_START + f"\n{line}\n" + AUTO_END + "\n")
